import{_ as s,W as a,X as l,Y as d,Z as e,$ as t,a0 as n,C as i}from"./framework-a4c02b8f.js";const _="/assets/images/BushiroadExpoAsia2023.jpeg",r={},c=e("p",null,"2023年3月24日～3月29日，我前往了香港，这也是我第一次出境，故将随感胡乱记下。",-1),h=e("figure",null,[e("img",{src:_,alt:"Bushiroad Expo Asia 2023",tabindex:"0",loading:"lazy"}),e("figcaption",null,"Bushiroad Expo Asia 2023")],-1),u=e("h1",{id:"物价差异",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#物价差异","aria-hidden":"true"},"#"),t(" 物价差异")],-1),p=e("p",null,"在大陆，一瓶普通的矿泉水只需¥2～3；而在香港的自动贩卖机与711之中，一瓶普通矿泉水的价格一般在HK$15左右，折合成人民币也是十几元。 可以说香港的所有饮料（包括罐装饮料）基本都在HK$10以上。",-1),f=e("p",null,"此外，餐厅与水果也普遍比大陆要贵，在茶楼吃早饭就能吃到人均HK¥200+。",-1),m=e("p",null,"还有一点是现居香港的友人喜欢强调的：奢侈品、数码产品等消费品的物价，由于税收和邮费等优势，确实也会比大陆便宜一些。",-1),x=e("h1",{id:"文化差异",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#文化差异","aria-hidden":"true"},"#"),t(" 文化差异")],-1),g=e("p",null,"各种告示牌主要是粤语与英语构成的，而商品感觉主要是由日本进口的（甚至包括一些在大陆被ban的东西）。",-1),B=e("p",null,"香港人主要讲粤语，但是当你尝试用普通话与其交流，他们也大多会用普通话来回应你。",-1),H=e("p",null,"印象比较深的是香港艺术馆，无需门票即可免费入场，入场后还能免费领取制作精良的导览册，其中还包括了立体的导览册，可以让你在打开每一页都能看到一个不同的瓷器，参观完甚至还会送你纪念品徽章。相比之下感觉是最良心的艺术馆了。",-1),K=e("h1",{id:"交通差异",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#交通差异","aria-hidden":"true"},"#"),t(" 交通差异")],-1),N=e("p",null,"香港的交通主要是地铁，巴士（包括双层大巴士、19人小巴士、叮叮车、露天巴士等）还有轮船。",-1),b=e("p",null,"香港的地铁卡（同时也是很泛用的NFC支付卡，在大多数场合都可以用来支付）叫做“八达通”，实际上地铁也确实很四通八达。每个地铁站会有很多分布在各地的出入口，地铁的车次也很多，还是相当方便的。",-1),v=e("p",null,"在大陆我没有体验过的交通方式是轮船，香港会有很廉价的“天星小轮”（经过涨价后一趟过海也只要HK$3.2），非常方便。",-1),$=e("p",null,"此外，香港的红绿灯并不会给你一个倒计时，但是它会通过铃声来提醒你。当你等待在红绿灯前，听到急促的铃声，你便知道你可以走了，此时十字路口四个方向的车都会停止等待，你无论是要去哪个方向的对面都可以出发了。当你听到铃声由急促变得愈发缓慢，你就知道红绿灯将要结束了。",-1),k=e("p",null,"（此外，有一个巴士同一个站点同一侧路牌居然有开往两个不同方向的车次，太逆天了）",-1),C=e("h1",{id:"总结",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#总结","aria-hidden":"true"},"#"),t(" 总结")],-1);function E(V,A){const o=i("Badge");return a(),l("div",null,[c,h,d(" more "),u,p,f,e("p",null,[t("但是，相比于北京，香港在海鲜类食物上还是有价格优势的。印象比较深的是Mr.Steak Buffet a la minute，HK$500即可吃到极为丰盛的海鲜自助（虽然它名字叫Mr.Steak，但是我感觉它更像是海鲜自助"),n(o,{text:"海鲜太多了！"}),t("）。")]),m,x,g,B,H,e("p",null,[t("另外，有一个细节，在餐厅吃饭时，服务员端上来的那一杯水，是用来给你清洗餐具用的……虽然我直接拿来喝了。"),n(o,{text:"这水确实也是可饮用的"})]),K,N,b,v,$,k,C,e("p",null,[t("总的来说，差异还是很多的，经过这一次旅行后，我发现北京的物价已经算低了，感觉生活变得更甜了。"),n(o,{text:"感恩",type:"danger"})])])}const y=s(r,[["render",E],["__file","TravelNotes_HongKong.html.vue"]]);export{y as default};
